# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import json
from websocket_server import WebsocketServer

# Define a simple in-memory database for player inventories
inventories = {}

# Function to handle incoming messages from clients
def message_received(client, server, message):
    data = json.loads(message)
    command = data.get('command')
    
    if command == 'get_inventory':
        player_id = data.get('player_id')
        inventory = inventories.get(player_id, {})
        server.send_message(client, json.dumps({'status': 'success', 'inventory': inventory}))
    
    elif command == 'transfer_item':
        sender_id = data.get('sender_id')
        receiver_id = data.get('receiver_id')
        item_id = data.get('item_id')
        
        if sender_id in inventories and item_id in inventories[sender_id]:
            # Remove the item from the sender's inventory
            item = inventories[sender_id].pop(item_id)
            
            # Add the item to the receiver's inventory
            if receiver_id not in inventories:
                inventories[receiver_id] = {}
            inventories[receiver_id][item_id] = item
            
            server.send_message(client, json.dumps({'status': 'success', 'message': 'Item transferred'}))
        else:
            server.send_message(client, json.dumps({'status': 'error', 'message': 'Item transfer failed'}))

# Create a websocket server and assign the callback function
server = WebsocketServer(host='localhost', port=8080)
server.set_fn_message_received(message_received)

# Start the server
server.run_forever()